const config = $('Load Config').first().json;
const reddit = $('Fetch Reddit n8n').first().json;
const newsXml = $('Fetch Google News RSS').first().json?.data || '';

const redditTopics = [];
try {
  const posts = reddit?.data?.children || [];
  for (const p of posts) {
    const title = p?.data?.title;
    if (title && title.length > 15) {
      const clean = title.replace(/\[.*?\]/g, '').trim();
      redditTopics.push({ topic: clean, source: 'reddit_n8n', score: p.data.ups || 0 });
    }
  }
} catch (e) {}

const newsTopics = [];
const titleRegex = /<title><!\[CDATA\[(.*?)\]\]><\/title>/g;
let m;
while ((m = titleRegex.exec(newsXml)) !== null) {
  const t = m[1];
  if (t && !t.includes('Google News') && t.length > 20) {
    newsTopics.push({ topic: t.trim(), source: 'news', score: 50 });
  }
}

const seedTopics = [
  { topic: 'How to automate email follow-ups with Make.com', source: 'seed', score: 80 },
  { topic: 'n8n beginner workflow: connect ChatGPT to Google Sheets', source: 'seed', score: 79 },
  { topic: 'Make.com vs Zapier for small business in 2026', source: 'seed', score: 78 },
  { topic: 'Best no-code AI automation tools ranked', source: 'seed', score: 77 },
  { topic: 'Automate client onboarding without coding', source: 'seed', score: 76 }
];

const combined = [...redditTopics, ...newsTopics, ...seedTopics].sort((a, b) => b.score - a.score).slice(0, 40);
return [{ json: { ...config, rawTopics: combined, rawCount: combined.length } }];

