const config = $('Merge Topic Sources').first().json;
const ai = $input.first().json;
let topics = [];
try {
  const content = ai.choices[0].message.content;
  const parsed = JSON.parse(content);
  topics = parsed.topics || parsed;
} catch (e) {
  throw new Error('Failed to parse OpenAI topic response: ' + e.message);
}
if (!Array.isArray(topics)) topics = [topics];
const { randomUUID } = require('crypto');
const now = new Date();
const delayMinutes = 72;
const queueItems = topics.slice(0, config.videosPerDay).map((t, i) => {
  const scheduled = new Date(now.getTime() + i * delayMinutes * 60 * 1000);
  return {
    queue_id: randomUUID(),
    status: 'pending',
    topic: t.topic || t,
    source: t.source || 'ai_generated',
    priority: t.priority || (10 - i),
    retry_count: 0,
    scheduled_at: scheduled.toISOString(),
    started_at: '',
    completed_at: '',
    error_message: ''
  };
});
return queueItems.map(item => ({ json: item }));
